export const getCreateStatUrl = () => {
  return `/api/stats`;
};

export const createStat = async (
  createStatBody: CreateStatBody,
  options?: RequestInit,
): Promise<GameStat> => {
  return customFetch<GameStat>(getCreateStatUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createStatBody),
  });
};

export const getCreateStatMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createStat>>,
    TError,
    { data: BodyType<CreateStatBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createStat>>,
  TError,
  { data: BodyType<CreateStatBody> },
  TContext
> => {
  const mutationKey = ["createStat"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createStat>>,
    { data: BodyType<CreateStatBody> }
  > = (props) => {
    const { data } = props ?? {};

    return createStat(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

